import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import type { SubmitHandler } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { z } from 'zod';
import { Mail, Lock, Loader2 } from 'lucide-react';

import { authService as accountService } from '@/api/auth/authService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { LoginPayloadSchema } from '@/types/schemas';

import { AuthLayout } from '../layouts/AuthLayout';
import { Button } from '@/shadcn/components/ui/button';
import { Card, CardContent } from '@/shadcn/components/ui/card';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { OtpComponent } from '@/components/shared/Otp';
import { useAuth } from '@/shared/AuthContext';

type LoginFormData = z.infer<typeof LoginPayloadSchema>;

function Login() {
  const [isOtpStage, setIsOtpStage] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [cooldown, setCooldown] = useState(0);

  const navigate = useNavigate();
  const { login } = useAuth();

  const {
    register,
    handleSubmit,
    setValue,
    formState: { errors },
  } = useForm<LoginFormData>({
    resolver: zodResolver(LoginPayloadSchema),
    mode: 'onChange',
    defaultValues: {
      email: '',
      password: '',
      rememberMe: false,
    },
  });

  // Countdown for brute-force protection
  useEffect(() => {
    if (cooldown <= 0) return;
    const id = setTimeout(() => setCooldown((s) => s - 1), 1000);
    return () => clearTimeout(id);
  }, [cooldown]);

  const extractWaitSeconds = (msg: string): number => {
    const match = msg.match(/(\d+)\s*second/i);
    return match ? parseInt(match[1], 10) : 0;
  };

  const loginMutation = useMutation({
    mutationFn: (credentials: LoginFormData) => accountService.login(credentials),
    onSuccess: async (response, variables) => {
      setCooldown(0);
      if (response.requiresOtp) {
        setUserEmail(variables.email);
        setIsOtpStage(true);
      } else {
        await login(response.authResult);
        navigate('/dashboard');
      }
    },
    onError: (err) => {
      const msg = getApiErrorMessage(err, '');
      const secs = extractWaitSeconds(msg);
      if (secs > 0) setCooldown(secs);
    },
  });

  useEffect(() => {
    const savedEmail = localStorage.getItem('harmony_remembered_email');
    if (savedEmail) {
      setValue('email', savedEmail);
      setValue('rememberMe', true);
    }
  }, [setValue]);

  const onSubmit: SubmitHandler<LoginFormData> = (data) => {
    if (cooldown > 0) return;
    loginMutation.mutate(data);
  };

  return (
    <AuthLayout>
      <Card className="glass-card border-0 ring-0 shadow-none min-h-[450px]">
        <CardContent className="flex flex-col justify-center min-h-[450px] px-6 py-8">
          {!isOtpStage ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="text-center mb-8">
                <h2 className="text-2xl font-black text-foreground tracking-tight">
                  Welcome Back
                </h2>
                <p className="text-sm text-muted-foreground mt-1">
                  Enter your credentials to access Harmony
                </p>
              </div>

              {cooldown > 0 && (
                <div className="mb-6 p-4 rounded-2xl bg-warning/10 border border-warning/20 flex items-center gap-4">
                  <div className="w-12 h-12 rounded-xl bg-warning/20 flex items-center justify-center text-xl font-black text-warning">
                    {cooldown}s
                  </div>
                  <div>
                    <p className="text-sm font-bold text-warning">Cooldown Active</p>
                    <p className="text-xs text-warning/80">Please wait before trying again.</p>
                  </div>
                </div>
              )}

              <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
                <HarmonyInput
                  label="Email Address"
                  type="email"
                  placeholder="name@company.com"
                  leftIcon={<Mail size={18} />}
                  error={errors.email?.message}
                  {...register('email')}
                />

                <HarmonyInput
                  label="Password"
                  type="password"
                  placeholder="••••••••"
                  leftIcon={<Lock size={18} />}
                  error={errors.password?.message}
                  {...register('password')}
                />

                <div className="flex items-center justify-between">
                  <label className="flex items-center gap-2 cursor-pointer group">
                    <div className="relative flex items-center">
                      <input
                        type="checkbox"
                        {...register('rememberMe')}
                        className="peer sr-only"
                      />
                      <div className="w-5 h-5 rounded-md border-2 border-border peer-checked:bg-primary peer-checked:border-primary transition-all"></div>
                      <svg className="absolute w-3.5 h-3.5 text-primary-foreground scale-0 peer-checked:scale-100 transition-transform left-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    </div>
                    <span className="text-sm font-medium text-muted-foreground group-hover:text-foreground transition-colors">
                      Remember me
                    </span>
                  </label>

                  <Link
                    to="/forgot-password"
                    className="text-sm font-bold text-primary hover:text-primary/80 transition-colors"
                  >
                    Forgot Password?
                  </Link>
                </div>

                <Button
                  type="submit"
                  className="w-full py-3.5"
                  disabled={loginMutation.isPending || cooldown > 0}
                >
                  {loginMutation.isPending && <Loader2 className="animate-spin" />}
                  {cooldown > 0 ? `Retry in ${cooldown}s` : 'Sign In'}
                </Button>
              </form>
            </div>
          ) : (
            <div className="animate-in fade-in slide-in-from-right-8 duration-500">
              <OtpComponent email={userEmail} />
              <button
                onClick={() => setIsOtpStage(false)}
                className="mt-8 w-full text-center text-sm font-bold text-muted-foreground hover:text-primary transition-colors"
              >
                ← Back to Login
              </button>
            </div>
          )}
        </CardContent>
      </Card>
    </AuthLayout>
  );
}

export default Login;
